using Dapper;
using Microsoft.Extensions.Logging;
using Valora.Application.Contracts;
using Valora.Application.DTOs;
using Valora.Application.ReadModels;
using Valora.Application.Security;
namespace Valora.Infrastructure.Repositories;
public sealed class SurveyRepository(IDbConnectionFactory f, ILogger<SurveyRepository> logger):ISurveyRepository
{
    public async Task<SurveyPublicReadModel?> GetPublicByTokenAsync(string token){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyPublicReadModel>(BaseSql+" AND s.token_hash=@token",new{token});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar pesquisa pública por token. Token={Token}",LogSanitizer.MaskToken(token));throw;}}
    public async Task<SurveyPublicReadModel?> GetActivePublicSurveyAsync(Guid surveyId){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyPublicReadModel>(BaseSql+" AND s.id=@surveyId",new{surveyId});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar pesquisa pública ativa. SurveyId={SurveyId}",surveyId);throw;}}
    public async Task<SurveyLinkReadModel?> GetPublicLinkAsync(Guid surveyId){try{using var c=f.Create(); return await c.QuerySingleOrDefaultAsync<SurveyLinkReadModel>("SELECT id,survey_id AS SurveyId,public_url AS PublicUrl,status,starts_at AS StartsAt,expires_at AS ExpiresAt FROM valorapesquisa.survey_links WHERE survey_id=@surveyId AND is_deleted=false AND status='active' AND (starts_at IS NULL OR starts_at<=now()) AND (expires_at IS NULL OR expires_at>now()) ORDER BY created_at DESC LIMIT 1",new{surveyId});}catch(Exception ex){logger.LogError(ex,"Erro ao buscar link público ativo. SurveyId={SurveyId}",surveyId);throw;}}
    public async Task<bool> ValidatePublicTokenAsync(Guid surveyId,string token){try{using var c=f.Create(); var ok=await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.survey_links WHERE survey_id=@surveyId AND token_hash=@token AND status='active' AND is_deleted=false AND (expires_at IS NULL OR expires_at>now())",new{surveyId,token}); if(ok>0)return true; return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.surveys WHERE id=@surveyId AND token_hash=@token AND is_deleted=false",new{surveyId,token})>0;}catch(Exception ex){logger.LogError(ex,"Erro ao validar token público. SurveyId={SurveyId} Token={Token}",surveyId,LogSanitizer.MaskToken(token));throw;}}
    public async Task<Guid> SaveResponseAsync(Guid surveyId,SubmitResponseRequest request){try{using var c=f.Create(); var survey=await GetActivePublicSurveyAsync(surveyId); if(survey is null) throw new InvalidOperationException("Pesquisa pública indisponível para submissão."); var id=Guid.NewGuid(); await c.ExecuteAsync("INSERT INTO valorapesquisa.responses(id,organization_id,survey_id,form_id,participant_name,participant_email,status,completed_at) VALUES (@id,@organizationId,@surveyId,@formId,@participantName,@participantEmail,'completed',now())",new{id,organizationId=survey.OrganizationId,surveyId,formId=survey.FormId,participantName=request.ParticipantName,participantEmail=request.ParticipantEmail}); logger.LogInformation("Resposta pública salva por rota compatível. SurveyId={SurveyId} ResponseId={ResponseId}",surveyId,id); return id;}catch(Exception ex){logger.LogError(ex,"Erro ao salvar resposta pública compatível. SurveyId={SurveyId} Email={Email}",surveyId,LogSanitizer.MaskEmail(request.ParticipantEmail));throw;}}
    public async Task<int> CountActiveSurveysAsync(Guid organizationId){try{using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.surveys WHERE organization_id=@organizationId AND status='active' AND is_deleted=false",new{organizationId});}catch(Exception ex){logger.LogError(ex,"Erro ao contar pesquisas ativas. OrganizationId={OrganizationId}",organizationId);throw;}}
    public async Task<int> CountResponsesThisMonthAsync(Guid organizationId){try{using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valorapesquisa.responses WHERE organization_id=@organizationId AND created_at >= date_trunc('month', now()) AND is_deleted=false",new{organizationId});}catch(Exception ex){logger.LogError(ex,"Erro ao contar respostas do mês. OrganizationId={OrganizationId}",organizationId);throw;}}
    const string BaseSql="SELECT s.id,s.organization_id AS OrganizationId,s.form_id AS FormId,s.title,s.description,s.status,s.lgpd_required AS LgpdRequired,o.name AS OrganizationName,o.public_name AS PublicName,o.slug AS OrganizationSlug,s.starts_at AS StartsAt,s.expires_at AS ExpiresAt FROM valorapesquisa.surveys s JOIN valorapesquisa.organizations o ON o.id=s.organization_id WHERE s.is_deleted=false AND s.status IN ('active','published','open') AND (s.starts_at IS NULL OR s.starts_at<=now()) AND (s.expires_at IS NULL OR s.expires_at>now())";
}
